  margin: 0;
  font-size: clamp(2rem, 4vw, 3rem);
}

.hero-copy {
  max-width: 650px;
  margin: 12px 0 0;
  line-height: 1.6;
  color: var(--muted);
}

.countdown-card {
  margin-top: 24px;
  padding: 18px 20px;
  border-radius: 16px;
  background: rgba(255, 248, 238, 0.1);
  display: inline-block;
  border: 1px solid var(--border);
}

.countdown-card p {
  margin: 0 0 10px;
  color: var(--muted);
}

.countdown {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
}

.countdown > div {
  min-width: 84px;
  padding: 10px 12px;
  border-radius: 12px;
  background: rgba(255, 249, 239, 0.14);
  text-align: center;
}

.countdown strong {
  display: block;
  font-size: 1.2rem;
  color: var(--accent-2);
}

.countdown span {
  font-size: 0.8rem;
  color: var(--muted);
  text-transform: uppercase;
  letter-spacing: 0.12em;
}

.content-grid {
  display: grid;
  gap: 20px;
  margin-top: 24px;
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.panel {
  padding: 24px;
  border-radius: 20px;
  background: var(--card);
  border: 1px solid var(--border);
  box-shadow: 0 12px 30px rgba(0, 0, 0, 0.16);
}

.panel-heading h2 {
  margin: 0;
  font-size: 1.3rem;
}

.panel-heading p {
  margin: 6px 0 0;
  color: var(--muted);
}

.guest-list,
.drink-grid {
  display: grid;
  gap: 12px;
  margin-top: 18px;
}

.guest-card,
.drink-card {
  padding: 14px 16px;
  border-radius: 14px;
  background: rgba(255, 248, 238, 0.08);
  border: 1px solid rgba(255, 248, 238, 0.12);
}

.guest-card {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
}

.guest-meta {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.guest-name {
  font-weight: 700;
}

.badge {
  display: inline-block;
  padding: 4px 10px;
  border-radius: 999px;
  font-size: 0.8rem;
  color: #3a2432;
  background: var(--accent-2);
}

.badge.pending {
  background: #ffdcb3;
}

.drink-card h3 {
  margin: 0 0 6px;
  font-size: 1rem;
}

.drink-card p {
  margin: 0;
  color: var(--muted);
  line-height: 1.5;
}

@media (max-width: 760px) {
  .content-grid {
    grid-template-columns: 1fr;
  }

  .hero {
    padding: 24px;
  }
}
"}

{"filePath":"/workspaces/soiree-planner/script.js","content":"const guests = [
  { name: "Mina", status: "Confirmed", plusOne: "Yes" },
  { name: "Jordan", status: "Pending", plusOne: "No" },
  { name: "Sage", status: "Confirmed", plusOne: "Yes" },
  { name: "Rafi", status: "Confirmed", plusOne: "No" },
];

const drinks = [
  { night: "Night 1", name: "Golden Hour Spritz", note: "Sparkling wine, apricot, rosemary, and a sunset glow." },
  { night: "Night 2", name: "Moonlit Mango Cooler", note: "Rum, mango, lime, and a whisper of basil." },
  { night: "Night 3", name: "Starlight Basil Smash", note: "Gin, cucumber, lemon, and a crisp herb finish." },
];

const openingNight = new Date("2026-08-14T19:00:00");
const countdownElement = document.getElementById("countdown");
const guestListElement = document.getElementById("guest-list");
const drinkMenuElement = document.getElementById("drink-menu");

function renderGuests() {
  guestListElement.innerHTML = guests
    .map(
      (guest) => `
        <article class="guest-card">
          <div class="guest-meta">
            <span class="guest-name">${guest.name}</span>
            <span>Plus-one: ${guest.plusOne}</span>
          </div>
          <span class="badge ${guest.status === "Pending" ? "pending" : ""}">${guest.status}</span>
        </article>
      `
    )
    .join("");
}

function renderDrinks() {
  drinkMenuElement.innerHTML = drinks
    .map(
      (drink) => `
        <article class="drink-card">
          <h3>${drink.night}: ${drink.name}</h3>
          <p>${drink.note}</p>
        </article>
      `
    )
    .join("");
}

function updateCountdown() {
  const now = new Date();
  const diff = openingNight - now;

  if (diff <= 0) {
    countdownElement.innerHTML = "<div><strong>Tonight</strong><span>is glowing</span></div>";
    return;
  }

  const days = Math.floor(diff / (1000 * 60 * 60 * 24));
  const hours = Math.floor((diff / (1000 * 60 * 60)) % 24);
  const minutes = Math.floor((diff / (1000 * 60)) % 60);
  const seconds = Math.floor((diff / 1000) % 60);

  countdownElement.innerHTML = `
    <div><strong>${days}</strong><span>days</span></div>
    <div><strong>${hours}</strong><span>hours</span></div>
    <div><strong>${minutes}</strong><span>mins</span></div>
    <div><strong>${seconds}</strong><span>secs</span></div>
  `;
}

renderGuests();
renderDrinks();
updateCountdown();
setInterval(updateCountdown, 1000);
"}

